1	schueco-table-3-2026	3	33	legacy-run-7-trend-33	Green Standards (China)	5	bekannt, nicht aktiv	5	{"summary": "China is actively developing a national standard for green buildings to address rising demands for new construction and associated energy consumption. The country has established around 70 assessment standards that focus on energy-saving and emission reduction, reflecting its commitment to sustainable urbanization.", "evidence": [{"url": "https://openalex.org/W1600554892", "title": "An Overview of Chinese Green Building Standards"}, {"url": "https://www.mdpi.com/2071-1050/14/19/12293", "title": "A Systematic Review of Green Building Development in China - MDPI"}, {"url": "https://openalex.org/W2786102023", "title": "A Review of Green Building Development in China from the Perspective of Energy Saving"}, {"url": "https://www.eusmecentre.org.cn/publications/the-green-building-sector-in-china-2/", "title": "The Green Building Sector in China | EU SME Centre"}, {"url": "https://openalex.org/W4323923315", "title": "A comparative analysis of green building rating systems in China and the United States"}, {"url": "https://worldgbc.org/wp-content/uploads/2022/02/Introduction-to-China-Green-Building-Assessment-Standard-3rd-Edition.pdf", "title": "[PDF] Introduction to China Green Building Assessment Standard 3rd Edition"}], "maturity": "established", "assessment": {"id": 33, "impact": 8.28, "pestel": ["environmental", "political"], "urgency": 6.446707169214884, "category": "climate", "trend_id": 33, "rationale": "The advancement of national green building standards in China presents significant implications for the building industry by promoting sustainability and energy efficiency, necessitating timely adaptation by companies, yet the specific outcomes and timelines are somewhat predictable.", "radar_stage": "act", "uncertainty": 4.420060753822327}, "machine_title": "China Advances National Green Building Standards"}
2	schueco-table-3-2026	1	34	legacy-run-7-trend-34	Adaptive Reuse	4	bekannt, nicht aktiv	5	{"summary": "Adaptive reuse of historic buildings promotes sustainability by integrating modern energy-efficient design with heritage preservation. This approach not only supports climate protection efforts but also advances the circular economy by minimizing resource extraction and waste.", "evidence": [{"url": "https://ecosteel.com/ecosteelprefab/embracing-regenerative-design-building-for-the-future/", "title": "Embracing Regenerative Design: Building for the Future of Our Planet"}, {"url": "https://openalex.org/W1560010907", "title": "Improving the implementation of adaptive reuse strategies for historic buildings"}, {"url": "https://www.c40knowledgehub.org/s/topic/0TO1Q0000001lSsWAI/commercial-building-retrofits?language=en_US", "title": "Commercial Building Retrofits - C40 Knowledge Hub"}, {"url": "https://openalex.org/W2980752769", "title": "Circular economy strategies for adaptive reuse of cultural heritage buildings to reduce environmental impacts"}, {"url": "https://www.linkedin.com/pulse/regenerative-design-approach-building-construction-ifyalem-", "title": "THE REGENERATIVE DESIGN APPROACH IN BUILDING ..."}, {"url": "https://www.sciencedirect.com/science/article/pii/S1877705815020603", "title": "Regenerative Design of Existing Buildings for Net-Zero Energy Use"}], "maturity": "established", "assessment": {"id": 34, "impact": 8.4, "pestel": ["environmental", "social"], "urgency": 6.075622379779816, "category": "climate", "trend_id": 34, "rationale": "The adaptive reuse of buildings significantly contributes to climate resilience and sustainability, garnering increasing attention from social and environmental perspectives, which necessitates timely action but has a moderate level of unpredictability based on market acceptance and regulatory frameworks.", "radar_stage": "act", "uncertainty": 4.1134335696697235}, "machine_title": "Adaptive Reuse Enhances Climate Resilience in Buildings"}
